const BLANK={kData:{},biz:{industry:"other"},cont:{},wealth:{},overrides:{}};

// ═══ BUSINESS VALUATION MODE (independent of Exit Planning) ════════════════════
// ═══ Multiple valuation methods (for the methods comparison chart) ═════════════
function calcMethods(biz, overrides, v){
  const ind=INDUSTRIES[biz.industry]||INDUSTRIES.other;
  const sde=v.sde, ebitda=v.ebitda;
  const ebitdaMid=((overrides.ebitdaMin??ind.ebitdaMin)+(overrides.ebitdaMax??ind.ebitdaMax))/2;
  const capRate=overrides.capRate??0.33;
  const discRate=overrides.discRate??0.25;
  const bookValue=overrides.bookValue??0;
  let g=calcGrowthRate(biz); if(!isFinite(g)||g==null) g=0; g=Math.max(-0.05,Math.min(0.15,g));
  const debt=v.bizDebt||0;
  const sdeMult=v.posMult;
  const fin=(x)=>Number.isFinite(x)&&x>0?x:0;
  const sdeVal=fin(sde*sdeMult - debt);
  const ebitdaVal=fin(ebitda*ebitdaMid - debt);
  const capVal=fin(sde/capRate - debt);
  let pv=0; for(let t=1;t<=5;t++){ pv+=(sde*Math.pow(1+g,t))/Math.pow(1+discRate,t); }
  const term=(discRate>0.03)?(sde*Math.pow(1+g,5)*sdeMult)/Math.pow(1+discRate,5):0;
  const dcfVal=fin(pv+term - debt);
  return [
    {name:"Asset / Book Value", value:fin(bookValue), note:bookValue?"Net tangible assets (advisor-entered)":"Not calculated — needs balance sheet", notCalc:!bookValue},
    {name:"Capitalization of Earnings", value:capVal, note:"Owner earnings \u00F7 "+Math.round(capRate*100)+"% cap rate"},
    {name:"EBITDA Multiple", value:ebitdaVal, note:"Operating profit \u00D7 "+ebitdaMid.toFixed(1)+"\u00D7"},
    {name:"Discounted Cash Flow", value:dcfVal, note:"5-yr cash flow + sale, "+Math.round(discRate*100)+"% discount"},
    {name:"Discretionary Earnings Multiple", value:sdeVal, note:"Owner earnings \u00D7 "+sdeMult.toFixed(1)+"\u00D7 (best fit)", recommended:true},
  ];
}

function wrapLabel(s){const w=s.split(" ");const lines=[];let cur="";w.forEach(word=>{if((cur+" "+word).trim().length>14){lines.push(cur.trim());cur=word;}else{cur=(cur+" "+word).trim();}});if(cur)lines.push(cur);return lines.slice(0,2);}

function scoreWord(s){ if(s>=75)return{word:"Strong",color:"#2E7D52",dark:"#7fd4a8"}; if(s>=60)return{word:"Good",color:"#5a9e6f",dark:"#9fdcb8"}; if(s>=45)return{word:"Average",color:"#C77D12",dark:"#f0c068"}; return{word:"Needs work",color:"#B23A2E",dark:"#ff9e90"}; }

function MethodsChart({methods}){
  const rec=methods.find(m=>m.recommended);
  const anchor=rec&&rec.value?rec.value:Math.max(...methods.map(m=>m.value),1);
  const realVals=methods.filter(m=>!m.notCalc).map(m=>m.value);
  const ceiling=Math.max(anchor*1.6, Math.max(...realVals,1)*0.0+anchor*1.6, 1);
  const W=720,H=300,padT=46,padB=82,padL=16,padR=16,gap=16;
  const n=methods.length, bw=(W-padL-padR-gap*(n-1))/n, yBot=H-padB, chartH=yBot-padT;
  return(<svg viewBox={"0 0 "+W+" "+H} style={{width:"100%",height:"auto",fontFamily:"'Nunito',sans-serif"}}>
    {methods.map((m,i)=>{const x=padL+i*(bw+gap);
      if(m.notCalc){return(<g key={i}>
        <rect x={x} y={yBot-3} width={bw} height={3} rx={1} fill={C.creamDark}/>
        <text x={x+bw/2} y={yBot-12} textAnchor="middle" fontSize="13" fontWeight="700" fill={C.slateLight}>n/a</text>
        {wrapLabel(m.name).map((ln,k)=><text key={k} x={x+bw/2} y={yBot+18+k*13} textAnchor="middle" fontSize="11" fill={C.slateLight}>{ln}</text>)}
        <text x={x+bw/2} y={yBot+18+wrapLabel(m.name).length*13+2} textAnchor="middle" fontSize="9.5" fill={C.slateLight}>needs balance sheet</text>
      </g>);}
      const capped=Math.min(m.value,ceiling); const h=Math.max(3,(capped/ceiling)*chartH); const y=yBot-h;
      const over=m.value>ceiling*1.02; const fill=m.recommended?C.gold:C.slateLight;
      return(<g key={i}>
        <rect x={x} y={y} width={bw} height={h} rx={4} fill={fill}/>
        {over&&<text x={x+bw/2} y={y-23} textAnchor="middle" fontSize="12" fill={fill}>▲</text>}
        <text x={x+bw/2} y={y-9} textAnchor="middle" fontSize="15" fontWeight="800" fill={m.recommended?C.navy:C.slate}>{fmtM(m.value)}</text>
        {wrapLabel(m.name).map((ln,k)=><text key={k} x={x+bw/2} y={yBot+18+k*13} textAnchor="middle" fontSize="11" fill={C.slate}>{ln}</text>)}
        {m.recommended&&<text x={x+bw/2} y={yBot+18+wrapLabel(m.name).length*13+2} textAnchor="middle" fontSize="10" fontWeight="700" fill={C.gold}>★ Best fit</text>}
      </g>);})}
    <line x1={padL} x2={W-padR} y1={yBot} y2={yBot} stroke={C.creamDark} strokeWidth="1.5"/>
  </svg>);
}

